if (!requireNamespace("jsonlite", quietly = TRUE)) {
  cat("&lt;p&gt;&lt;em&gt;jsonlite package is required to render this page.&lt;/em&gt;&lt;/p&gt;")
} else if (!requireNamespace("leaflet", quietly = TRUE)) {
  cat("&lt;p&gt;&lt;em&gt;leaflet package is required to render this page.&lt;/em&gt;&lt;/p&gt;")
} else {
  tracks_dir &lt;- "outputs/sim_tracks"
  events_dir &lt;- "outputs/sim_events"
  runs &lt;- list.files(tracks_dir, pattern = "\\.csv$", full.names = TRUE)
  run_names &lt;- sub("\\.csv$", "", basename(runs))
  tracks &lt;- list()
  for (i in seq_along(runs)) {
    d &lt;- utils::read.csv(runs[[i]], stringsAsFactors = FALSE)
    if (nrow(d) == 0) next
    tracks[[run_names[[i]]]] &lt;- d
  }

  chargers &lt;- data.frame()
  if (file.exists("data/chargers_cached.csv")) {
    chargers &lt;- utils::read.csv("data/chargers_cached.csv", stringsAsFactors = FALSE)
  }

  payload &lt;- list(
    runs = tracks,
    chargers = chargers
  )

  cat('&lt;div id="sim-controls" style="display:flex;gap:12px;align-items:center;flex-wrap:wrap"&gt;')
  cat('&lt;label&gt;Run &lt;select id="run-picker"&gt;&lt;/select&gt;&lt;/label&gt;')
  cat('&lt;button id="play-btn"&gt;Play&lt;/button&gt;')
  cat('&lt;label&gt;Speed &lt;input id="speed-range" type="range" min="1" max="100" value="20"&gt;&lt;/label&gt;')
  cat('&lt;span id="speed-label"&gt;20x&lt;/span&gt;')
  cat('&lt;/div&gt;')
  cat('&lt;div style="display:grid;grid-template-columns:2fr 1fr;gap:12px;margin-top:12px"&gt;')
  cat('&lt;div id="map" style="height:600px"&gt;&lt;/div&gt;')
  cat('&lt;div id="counters" style="font-family:monospace"&gt;&lt;/div&gt;')
  cat('&lt;/div&gt;')
  cat(sprintf('&lt;script&gt;window.routeSimPayload=%s;&lt;/script&gt;', jsonlite::toJSON(payload, dataframe = "rows", auto_unbox = TRUE, na = "null")))
  cat('&lt;script src="assets/route_sim_animation.js"&gt;&lt;/script&gt;')
}

&lt;div id="sim-controls" style="display:flex;gap:12px;align-items:center;flex-wrap:wrap"&gt;&lt;label&gt;Run &lt;select id="run-picker"&gt;&lt;/select&gt;&lt;/label&gt;&lt;button id="play-btn"&gt;Play&lt;/button&gt;&lt;label&gt;Speed &lt;input id="speed-range" type="range" min="1" max="100" value="20"&gt;&lt;/label&gt;&lt;span id="speed-label"&gt;20x&lt;/span&gt;&lt;/div&gt;&lt;div style="display:grid;grid-template-columns:2fr 1fr;gap:12px;margin-top:12px"&gt;&lt;div id="map" style="height:600px"&gt;&lt;/div&gt;&lt;div id="counters" style="font-family:monospace"&gt;&lt;/div&gt;&lt;/div&gt;&lt;script&gt;window.routeSimPayload={"runs":[],"chargers":[]};&lt;/script&gt;&lt;script src="assets/route_sim_animation.js"&gt;&lt;/script&gt;
